import { inject, Injectable } from '@angular/core';
import {
  EventName,
  MessageBusService,
  Parent,
  School,
  Student,
} from '@zdc/main';
import { firstValueFrom } from 'rxjs';

@Injectable({
  providedIn: 'root',
})
export class ClientBridgeService {
  private readonly messageBusService = inject(MessageBusService);

  /** Specific */

  getStudent(): Promise<Student> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET_STUDENT),
    );
  }

  getParent(): Promise<Parent> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET_PARENT),
    );
  }

  getAccessToken(): Promise<string> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET_ACCESS_TOKEN),
    );
  }

  getSchool(): Promise<School> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET_SCHOOL),
    );
  }

  gotoPaymentSummary(
    payload: Record<string, unknown>,
  ): Promise<Record<string, unknown>> {
    return firstValueFrom(
      this.messageBusService.emitRequest(
        EventName.GOTO_PAYMENT_SUMMARY,
        payload,
      ),
    );
  }

  /** Generic */

  get(
    action: string,
    payload?: Record<string, unknown>,
  ): Promise<Record<string, unknown>> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET, { action, payload }),
    );
  }

  send(
    action: string,
    payload?: Record<string, unknown>,
  ): Promise<Record<string, unknown>> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.SEND, { action, payload }),
    );
  }

  goto(
    action: string,
    payload?: Record<string, unknown>,
  ): Promise<Record<string, unknown>> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GOTO, { action, payload }),
    );
  }
}
