import { Inject, Injectable } from '@angular/core';
import { CoreFeature } from '@zdc/main';
import { CORE_FEATURE } from '@zdc/main/host';

@Injectable({ providedIn: 'root' })
export class CoreFeatureService {
  constructor(@Inject(CORE_FEATURE) private readonly services: CoreFeature) {}

  getApiService() {
    return this.services.apiService;
  }

  getParentStateManager() {
    return this.services.parentStateManager;
  }
}
